import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { AdminService, UserOut } from '../../core/admin';

@Component({
  selector: 'app-admin',
  imports: [CommonModule, FormsModule],
  styles: ``,
  templateUrl: './admin.html',
})
export class Admin implements OnInit {
  private svc = inject(AdminService);

  users: UserOut[] = [];
  loading = false;
  error = '';

  editingId: number | null = null;
  editUsername = '';
  editPassword = '';

  ngOnInit() { this.load(); }

  load() {
    this.loading = true;
    this.svc.listUsers().subscribe({
      next: u => { this.users = u; this.loading = false; },
      error: () => { this.error = 'Error al cargar usuarios.'; this.loading = false; },
    });
  }

  startEdit(user: UserOut) {
    this.editingId = user.id;
    this.editUsername = user.username;
    this.editPassword = '';
  }

  saveEdit(id: number) {
    const body: { username?: string; password?: string } = {};
    if (this.editUsername) body.username = this.editUsername;
    if (this.editPassword) body.password = this.editPassword;
    this.svc.updateUser(id, body).subscribe({
      next: () => { this.editingId = null; this.load(); },
      error: () => { this.error = 'Error al actualizar usuario.'; },
    });
  }

  deleteUser(id: number, username: string) {
    if (!confirm(`¿Eliminar al usuario "${username}" y todos sus documentos?`)) return;
    this.svc.deleteUser(id).subscribe(() => this.load());
  }
}
