import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';

const API = '/api';

export interface UserOut {
  id: number;
  username: string;
  is_admin: boolean;
}

@Injectable({ providedIn: 'root' })
export class AdminService {
  private http = inject(HttpClient);

  listUsers() {
    return this.http.get<UserOut[]>(`${API}/admin/users`);
  }

  deleteUser(id: number) {
    return this.http.delete(`${API}/admin/users/${id}`);
  }

  updateUser(id: number, body: { username?: string; password?: string }) {
    return this.http.patch<UserOut>(`${API}/admin/users/${id}`, body);
  }

  deleteDocument(id: number) {
    return this.http.delete(`${API}/admin/documents/${id}`);
  }
}
